def digit_sum(n):
    return sum(int(d) for d in str(n))

def is_magic(n):
    while n >= 10:
        n = digit_sum(n)
    return n == 1

print(is_magic(199))
print(is_magic(23))

def caesar(text, shift):
    result = ''
    for c in text:
        if c.isalpha():
            base = ord('a') if c.islower() else ord('A')
            result += chr((ord(c) - base + shift) % 26 + base)
        else:
            result += c
    return result

print(caesar('python', 3))
print(caesar('khoor', -3))

