def check_password(pwd):
    conditions = [
        len(pwd) >= 8,
        any(c.isupper() for c in pwd),
        any(c.islower() for c in pwd),
        any(c.isdigit() for c in pwd),
        any(c in '!@#$%^&*' for c in pwd)
    ]
    score = sum(conditions)
    if score == 5:
        return 'Strong 💪'
    elif score >= 3:
        return 'Medium 🟡'
    else:
        return 'Weak ❌'

